import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.io.*;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = reader.readLine();

        // Encode user input to prevent XSS
        String sanitizedInput = "";
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
            System.exit(1);
        }

        System.out.println("Hello, " + sanitizedInput + "!"); // Safe code

        // Other secure operations
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
